    for strip in game_sequence:
        strip_index = int(strip) - 1  # Convert to 0-indexed
        total_calories += calories[strip_index]
    return total_calories

def max_score_in_directed_graph(n: int, edges: list) -> str:
    # Convert edges to 0-indexed
    edge_list = [(a - 1, b - 1, -c) for a, b, c in edges]

    INF = float("inf")
    cost = [INF] * n
    cost[0] = 0

    negative_loop_exist = False
    for i in range(n):
        for j in range(len(edge_list)):
            a, b, c = edge_list[j]
            if cost[a] != INF and cost[b] > cost[a] + c:
                cost[b] = cost[a] + c
                if i == n - 1 and b == n - 1:
                    negative_loop_exist = True

    if negative_loop_exist:
        return "inf"
    else:
        return str(-cost[n - 1])

def min_boxes_to_open(n: int, box_contents: list, queries: list) -> list:
    mularr = []
    qm = max(queries)
    candy = box_contents[0]
    mularr.append([box_contents[0], 1])

    for b in box_contents[1:]:
        if b == 1:
            mularr[-1][1] += 1
        else:
            candy *= b
            mularr.append([candy, 1])
        if qm <= candy:
            break

    results = []
    for query in queries:
        cnt = n
        test = query
        test -= 1
        for k, v in mularr:
            add = (test // k) * v
            cnt += add
        results.append(cnt)

    return results

def min_travel_time(n: int, h: int, a: int, b: int, queries: list) -> list:
    results = []
    for query in queries:
        t1, f1, t2, f2 = query
        if t1 == t2:
            results.append(abs(f1 - f2))
        elif a <= f1 <= b:
            results.append(abs(t2 - t1) + abs(f2 - f1))
        elif f1 < a:
            results.append(abs(a - f1) + abs(t2 - t1) + abs(f2 - a))
        elif f1 > b:
            results.append(abs(b - f1) + abs(t2 - t1) + abs(f2 - b))
    return results

def count_substrings_divisible_by_4(s: str) -> int:
    ans = 0

    # Count single digits divisible by 4
    for x in s:
        if int(x) % 4 == 0:
            ans += 1

    # Count two or more digit substrings divisible by 4
    for i in range(1, len(s)):
        if int(s[i - 1: i + 1]) % 4 == 0:
            ans += i

    return ans

