def balance_scales(initial_state: str, remaining_weights: str) -> str:
    # Split the initial state into left and right pans
    left_pan = initial_state[:initial_state.find('|')]
    right_pan = initial_state[initial_state.find('|') + 1:]

    # Distribute remaining weights optimally
    n = 0
    while n < len(remaining_weights):
        if len(left_pan) < len(right_pan):
            left_pan += remaining_weights[n]
        else:
            right_pan += remaining_weights[n]
        n += 1

    # Check if equilibrium is possible
    if len(left_pan) == len(right_pan):
        return left_pan + '|' + right_pan
    else:
        return "Impossible"

def find_shortest_original_title(problem_titles: list) -> str:
    # Collect all substrings from the problem titles
    bad_strings = set()
    for title in problem_titles:
        for left in range(len(title)):
            for right in range(left + 1, len(title) + 1):
                bad_strings.add(title[left:right])

    # Generate possible titles in order of increasing length and lexicographic order
    alphabet = [chr(c) for c in range(ord('a'), ord('z') + 1)]

    # Try length 1 first
    for char in alphabet:
        if char not in bad_strings:
            return char

    # Try length 2 and beyond
    import itertools
    for length in range(2, 22):  # Maximum title length is 21
        for chars in itertools.product(alphabet, repeat=length):
            title = ''.join(chars)
            if title not in bad_strings:
                return title

def transform_string(s: str, a: list) -> str:
    s = list(s)
    n = len(s) // 2
    sums = [0] * (n + 1)

    for i in a:
        sums[i - 1] += 1

    for i in range(1, len(sums)):
        sums[i] += sums[i-1]

    for i in range(n):
        if (sums[i] % 2 == 1):
            s[i], s[-i-1] = s[-i-1], s[i]

    return "".join(s)

def check_valid_zombie_lair(grid):
    n = len(grid)
    x1, y1 = n, n
    x2, y2 = -1, -1

    # Find the bounding box of all cells with value 4
    for y in range(n):
        for x in range(n):
            if grid[y][x] == 4:
                x1 = min(x1, x)
                y1 = min(y1, y)
                x2 = max(x2, x)
                y2 = max(y2, y)

    # If no cells with value 4 found
    if x1 == n:
        return False

    # Check if the grid matches the expected pattern for a rectangular lair
    for y in range(n):
        for x in range(n):
            expected = 0
            if x1 <= x <= x2 and y1 <= y <= y2:
                expected = 4
            elif (x == x1-1 or x == x2+1) and y1 <= y <= y2:
                expected = 2
            elif (y == y1-1 or y == y2+1) and x1 <= x <= x2:
                expected = 2
            elif (x == x1-1 or x == x2+1) and (y == y1-1 or y == y2+1):
                expected = 1

            if expected != grid[y][x]:
                return False

    return True

