def compute_exclusive_or_range(a: int, b: int) -> int:
    if a % 2 == 0 and b % 2 == 0:
        if ((b - a) // 2) % 2 == 0:
            return 0 ^ b
        else:
            return 1 ^ b
    elif a % 2 == 0:
        if ((b - a + 1) // 2) % 2 == 0:
            return 0
        else:
            return 1
    elif b % 2 == 0:
        if ((b - a - 1) // 2) % 2 == 0:
            return 0 ^ a ^ b
        else:
            return 1 ^ a ^ b
    else:
        if ((b - a) // 2) % 2 == 0:
            return 0 ^ a
        else:
            return 1 ^ a

from collections import defaultdict

def min_battles_for_unique_order(n: int, battles: list) -> int:
    def check_order(num_battles):
        edge_map = defaultdict(list)
        rev_map = defaultdict(list)

        for i in range(num_battles):
            u, v = battles[i]
            edge_map[u-1].append((v-1, i))
            rev_map[v-1].append((u-1, i))

        outgoing_cnt = defaultdict(int)
        for k in edge_map:
            outgoing_cnt[k] = len(edge_map[k])

        s = []
        cntr = 0
        for i in range(n):
            if outgoing_cnt.get(i, 0) == 0:
                s.append(i)

        while len(s) > cntr:
            if len(s) > cntr+1:
                return False
            else:
                node = s[cntr]
                for v, _ in rev_map.get(node, []):
                    outgoing_cnt[v] -= 1
                    if outgoing_cnt[v] == 0:
                        s.append(v)
                cntr += 1

        return True

    # Check if there's a unique ordering after all battles
    if not check_order(len(battles)):
        return -1

    # Binary search for the minimum number of battles needed
    lo, hi = 0, len(battles)
    while lo < hi - 1:
        mid = (lo + hi) // 2
        if check_order(mid):
            hi = mid
        else:
            lo = mid

    return hi

def count_permutations_with_k_good_positions(n: int, k: int) -> int:
    mod = 10**9 + 7

    # Calculate factorial and its inverse
    F = [0] * (n + 1)
    G = [0] * (n + 1)
    F[0] = G[0] = 1
    for i in range(1, n + 1):
        F[i] = (F[i-1] * i) % mod
        G[i] = pow(F[i], mod - 2, mod)  # Fermat's little theorem for modular inverse

    # Calculate binomial coefficients
    B = [0] * (n + 1)
    for i in range(0, n):
        if i * 2 > n:
            break
        B[i] = (F[n-i] * G[i] * G[n-i*2]) % mod

    # Calculate A array
    A = [0] * (n + 1)
    for i in range(0, n//2 + 1):
        for j in range(0, n//2 + 1):
            A[i+j] = (A[i+j] + B[i] * B[j]) % mod

    for i in range(0, n + 1):
        A[i] = (A[i] * F[n-i]) % mod

    # Calculate C array
    C = [0] * (n + 1)
    for i in range(0, n + 1):
        for j in range(0, i + 1):
            C[j] = (C[j] + A[i] * F[i] * G[j] * G[i-j] * (1 - (i-j) % 2 * 2)) % mod

    return C[k] % mod

def compute_linear_function_iterations(a: int, b: int, n: int, x: int) -> int:
    MOD = 10**9 + 7

    # Calculate first part: a^n * x
    first_part = pow(a, n, MOD) * x % MOD

    # Calculate second part: b * (a^n - 1) / (a - 1)
    if a == 1:
        second_part = (n * b) % MOD
    else:
        second_part = (b * (pow(a, n, MOD) - 1) * pow(a - 1, MOD - 2, MOD)) % MOD

    return (first_part + second_part) % MOD

