    aidx = [-1] * n
    bidx = [-1] * n

    for i, (ai, bi) in enumerate(zip(a, b)):
        aidx[ai-1] = i
        bidx[bi-1] = i

    diffs = [(aidx[i] - bidx[i]) % n for i in range(n)]
    return max(Counter(diffs).values())

