    rest = n - t

    # First, fill positions where s1 and s2 have the same character
    for i in range(n):
        if rest == 0:
            break
        if s1[i] == s2[i]:
            result[i] = s1[i]
            rest -= 1

    # Then fill some of the remaining positions with characters from s1
    k = rest
    for i in range(n):
        if k == 0:
            break
        if result[i] == -1:
            result[i] = s1[i]
            k -= 1

    # Then fill some positions with characters from s2
    k = rest
    for i in range(n):
        if k == 0:
            break
        if result[i] == -1:
            result[i] = s2[i]
            k -= 1

    # If we still have positions to fill, it's impossible
    if k > 0:
        return "-1"

    # For remaining positions, choose a character different from both s1 and s2
    for i in range(n):
        if result[i] == -1:
