            a.pop()
            last = a[-1]
    a.pop(0)

    s1 = 0
    while len(a) > 0 and a[0][0] == a[-1][0]:
        if len(a) == 1:
            s = a[0][1] * m
            r1 = s % k
            if r1 == 0:
                return s1 % k
            else:
                return r1 + s1
        join = a[0][1] + a[-1][1]

        if join < k:
            break
        elif join % k == 0:
            s1 += join
            a.pop()
            a.pop(0)
        else:
