def find_kth_element(x: int, p: int, k: int) -> int:
    # Generate prime factors of p
    prime_factors = []
    i = 2
    temp_p = p
    while i * i <= temp_p:
        if temp_p % i == 0:
            prime_factors.append(i)
            while temp_p % i == 0:
                temp_p //= i
        i += 1
    if temp_p > 1:
        prime_factors.append(temp_p)

    # Generate inclusion-exclusion sets
    to_add = []
    to_subtract = []
    for i in range(1, 1 << len(prime_factors)):
        mul = 1
        count = 0
        for j in range(len(prime_factors)):
            if (1 << j) & i:
                count += 1
                mul *= prime_factors[j]

        if count % 2:
            to_add.append(mul)
        else:
            to_subtract.append(mul)

    # Count numbers <= x that are coprime with p
    count_before = 0
    for num in to_add:
        count_before += x // num

    for num in to_subtract:
        count_before -= x // num

    k += (x - count_before)

    # Binary search for the answer
    low = 0
    high = 10**9
    answer = high
    while low <= high:
        mid = (high + low) // 2
        temp_count = 0
        for num in to_add:
            temp_count += mid // num
        for num in to_subtract:
            temp_count -= mid // num
        temp_count = mid - temp_count
        if temp_count >= k:
            answer = min(answer, mid)
            high = mid - 1
        else:
            low = mid + 1

    return answer

def find_sets_of_rank_k(n: int, k: int) -> tuple:
    from math import gcd

    def check_set(set_k, new_val):
        for v in set_k:
            if gcd(v, new_val) != 1:
                return False
        return True

    j = 1
    sets = []
    for _ in range(n):
        set_k = set()
        while len(set_k) < 4:
            if check_set(set_k, j) and not (len(set_k) == 0 and j % 3 == 0):
                set_k.add(j)
            j += 1
        sets.append(list(set_k))

    max_val = max(max(s) for s in sets)
    result_sets = [[x * k for x in s] for s in sets]

    return (max_val * k, result_sets)

