        for i, x in enumerate(d):
            while x > stack[-1][1]:
                prev_i, prev_x = stack.pop()
                prev_prev_i, prev_prev_x = stack[-1]
                sum_ += prev_x * (i - prev_i) * (prev_i - prev_prev_i)
            stack.append((i, x))
        while len(stack) > 1:
            prev_i, prev_x = stack.pop()
            prev_prev_i, prev_prev_x = stack[-1]
            sum_ += prev_x * (len(d) - prev_i) * (prev_i - prev_prev_i)
        return sum_

    def max_differences_sum(d):
        return max_sums(d) + max_sums([-x for x in d])

    return max_differences_sum(arr)

def count_subsequences(n: int, sequence: list) -> list:
    mod = 10**9 + 7

    # Find the repeated element
    sorted_seq = sorted(sequence)
    for i in range(n):
        if sorted_seq[i] == sorted_seq[i+1]:
            duplicate = sorted_seq[i]
            break

    # Find positions of the duplicate element
    l, r = -1, -1
    for i in range(n+1):
        if l < 0:
            if sequence[i] == duplicate:
                l = i
        else:
            if sequence[i] == duplicate:
                r = i
                break

    # Calculate factorials and inverse factorials
    factorial = [1] * (n+2)
    factorial_inv = [1] * (n+2)
    for i in range(1, n+2):
        factorial[i] = (factorial[i-1] * i) % mod
        factorial_inv[i] = pow(factorial[i], mod-2, mod)

    # Function to calculate combinations
    def comb(n, k):
        if k < 0 or k > n:
            return 0
        return (factorial[n] * factorial_inv[k] * factorial_inv[n-k]) % mod

    results = []
    for k in range(1, n+2):
        ans = 0

        if k >= 2:
            ans = (ans + comb(n-1, k-2)) % mod

        if n - 1 >= k:
            ans = (ans + comb(n-1, k)) % mod

        if n >= k:
            ans = (ans + 2 * comb(n-1, k-1)) % mod

        if n + l - r >= k - 1:
            ans = (ans - comb(n+l-r, k-1)) % mod

        results.append(ans)

    return results

