def count_distinct_good_substrings(s: str, good_letters: str, k: int) -> int:
    # Create a set of good letters
    good = set()
    for i in range(26):
        if good_letters[i] == '1':
            good.add(chr(i + 97))  # 'a' is 97 in ASCII

    # Mark each character as bad (True) or good (False)
    t = [s[i] not in good for i in range(len(s))]

    # Find the rightmost position for each starting position
    end = [0] * len(s)
    badchars = 0
    front = 0
    rear = 0
    while front < len(s):
        while rear < len(s):
            badchars += t[rear]
            if badchars > k:
                badchars -= 1
                break
            rear += 1
        end[front] = rear
        badchars -= t[front]
        front += 1

    # Count distinct substrings using hashing
    string = set()
    for i in range(len(s)):
        temp_str_hash = 0
        for j in range(i, end[i]):
