    return len(string)

def min_vertical_paths(n: int, L: int, S: int, weights: list, parents: list) -> int:
    # Convert to 0-indexed
    weights = [w for w in weights]

    # Handle the special case of n=1
    if n == 1:
        return -1 if weights[0] > S else 1

    # Build the tree structure using children instead of parents
    children = [set() for _ in range(n)]
    for i, p in enumerate(parents):
        children[p-1].add(i+1)  # Convert to 0-indexed

    # Helper function to solve the problem
    def solve(n, l, s, weights, children):
        ans = 0
        dp = [{} for _ in range(n)]

        for v in range(n - 1, -1, -1):
            cv = children[v]
            if not cv:
                dp[v][1] = weights[v]
                continue

            ans += len(cv) - 1
            wv = weights[v]

            if wv > s:
                return -1

            dv = dp[v]
            for c in cv:
                for lc, wc in list(dp[c].items()):
                    if lc == l:
                        continue
                    wt = wc + wv
                    if wt > s:
                        continue
                    if lc + 1 not in dv:
                        dv[lc + 1] = wt
                    else:
                        dv[lc + 1] = min(dv[lc + 1], wt)

            if not dv:
                ans += 1
                dv[1] = wv

        return ans + 1

    return solve(n, L, S, weights, children)

