    if len(b) > len(a):
        return 0

    # Calculate initial hamming distance
    d = 0
    for i in range(len(b)):
        if a[i] != b[i]:
            d += 1

    # Calculate transitions between consecutive characters in b
    g = 0
    for i in range(1, len(b)):
        if b[i] != b[i-1]:
            g += 1

    # Count substrings with even hamming distance
    ans = 1 if d % 2 == 0 else 0

    for i in range(len(b), len(a)):
        # Update hamming distance for the next window
        if a[i] != b[-1]:
            d += 1
        if a[i - len(b)] != b[0]:
            d += 1
        d += g

        if d % 2 == 0:
            ans += 1

    return ans

