        i += 1

    min_ops = len(n)

    # Check each perfect square
    for square in perfect_squares:
        i = 0  # index for square
        j = 0  # index for n

        # Try to find square as a subsequence of n
        while i < len(square) and j < len(n):
            if square[i] == n[j]:
                i += 1
            j += 1

        # If we found all digits of the square as a subsequence
