def calculate_win_probability(p: int, s: int, r: int) -> int:
    base = 998244353

    def power(x, y):
        if y == 0:
            return 1
        t = power(x, y // 2)
        t = (t * t) % base
        if y % 2:
            t = (t * x) % base
        return t

    def inverse(x):
        return power(x, base - 2)

    # Precompute factorials and their inverses
    f = [1]
    iv = [1]
    for i in range(1, 5555):
        f.append((f[i-1] * i) % base)
        iv.append(inverse(f[i]))

    def C(n, k):
        return (f[n] * iv[k] * iv[n-k]) % base

    def candy(n, k):
        # Stars and bars formula
        return C(n + k - 1, k - 1)

    def count_game(k, n, x):  # k players, n points total, no player can have x point or more
        if k == 0:
            return 1 if n == 0 else 0

        ans = 0
        for i in range(0, k + 1):
            t = n - x * i
            if t < 0:
                break
            if i % 2:
                ans = (ans - C(k, i) * candy(t, k)) % base
            else:
                ans = (ans + C(k, i) * candy(t, k)) % base
        return ans

    gamesize = count_game(p, s - r, int(1e18))
    gamesize = inverse(gamesize)
    ans = 0

    for q in range(r, s + 1):
        for i in range(0, p):  # exactly i people have the same score
            t = s - (i + 1) * q
            if t < 0:
                break
            ans = (ans + C(p - 1, i) * count_game(p - i - 1, t, q) * gamesize * inverse(i + 1)) % base

    return ans

def nim_win_probability(n: int, x: int, probabilities: list) -> float:
    """
    Calculate the probability that the first player wins in a game of Nim.
    """
    def mult(a, b):
        # compute a*b
        c = [0] * 128
        for i in range(128):
            for j in range(128):
                c[i ^ j] += a[i] * b[j]
        return c

    def quickpow(a, b):
        # compute a**b
        if b == 1:
            return a
        if b & 1:
            return mult(quickpow(mult(a, a), b // 2), a)
        return quickpow(mult(a, a), b // 2)

    # Extend probabilities to length 128 by padding with zeros
    prob = probabilities + [0.0] * (128 - len(probabilities))

    # The probability of winning is 1 minus the probability that the nim-sum is 0
    return 1 - quickpow(prob, n)[0]

