    seen = set()
    result = []

    for name in names:
        if name in seen:
            result.append("YES")
        else:
            result.append("NO")
        seen.add(name)

    return result

def max_candies_for_arkady(n: int, k: int, M: int, D: int) -> int:
    ans = 0
    for d in range(1, D + 1):
        bot = 0
        top = M + 1
        while (top > bot + 1):
            mid = (bot + top) // 2
            cur = (d - 1) * mid * k
            cur += mid
            if (cur > n):
                top = mid
            else:
                bot = mid
        ans = max(ans, bot * d)
    return ans

def greatest_beautiful_divisor(n: int) -> int:
    ans = 1
    for k in range(1, 10):
        v = ((1 << k) - 1) * (1 << (k - 1))
        if n % v == 0:
            ans = v
    return ans

def find_last_number(arr: list) -> int:
    nums = arr.copy()
    n = len(nums)

    for i in range(n - 1):
        if i % 2 == 0:  # First player's turn (minimize)
            nums.pop(nums.index(max(nums)))
        else:  # Second player's turn (maximize)
            nums.pop(nums.index(min(nums)))

    return nums[0]

def is_good_lab(grid: list) -> str:
    n = len(grid)

    for i in range(n):
        for j in range(n):
            if grid[i][j] == 1:
                continue

            is_valid = False
            for s in range(n):
                for t in range(n):
                    if grid[i][j] == grid[i][s] + grid[t][j]:
                        is_valid = True
                        break
                if is_valid:
                    break

            if not is_valid:
                return "No"

    return "Yes"

def max_truth_speakers(statements):
    N = len(statements)
    count = 0

    for i in range(N):
        flag = 0
        value = statements[i].count('T')

        for j in range(N):
            if statements[i][j] == 'T' and i != j:
                if statements[i] == statements[j]:
                    continue
                else:
                    flag = 1
                    break

        if flag == 0 and count < value:
            count = value

    return count

def minimum_checkout_time(n: int, queues: list) -> int:
    times = []
    for people in queues:
        time = len(people) * 15
        for p in people:
            time += p * 5
        times.append(time)
    return min(times)

def find_n_with_loops(k: int) -> int:
    if k // 2 + k % 2 > 18:
        return -1
    else:
        return int('8' * (k // 2) + ('6' if k % 2 else ''))

def smallest_array_after_swaps(arr: list) -> list:
    odd = 0
    even = 0

    for i in arr:
        if i % 2:
            odd += 1
        else:
            even += 1

    if even == 0 or odd == 0:
        return arr
    else:
        return sorted(arr)

def min_operations_for_equal_elements(n: int, x: int, arr: list) -> int:
    # Check if there are already duplicate elements
    if len(arr) != len(set(arr)):
        return 0

    # Try applying one operation to see if we can get duplicates
    for i in range(n):
        modified_arr = arr.copy()
        modified_arr[i] = arr[i] & x
        if len(modified_arr) != len(set(modified_arr)):
            return 1

    # Try applying two operations to see if we can get duplicates
    modified_arr = [a & x for a in arr]
    if len(modified_arr) != len(set(modified_arr)):
        return 2

    # If it's not possible with 0, 1, or 2 operations
    return -1

def create_beautiful_string(s: str) -> str:
    def get_not(arr):
        for x in ['a', 'b', 'c']:
            if x not in arr:
                return x
        return None  # Should not happen with valid inputs

    s_list = list(s)
    n = len(s_list)

    # Check if it's impossible to create a beautiful string
    for i in range(n - 1):
        if s_list[i] == s_list[i + 1] and s_list[i] != '?':
            return "-1"

    # Replace question marks
    for i in range(n):
        if s_list[i] == '?':
            avoid = []
            if i > 0 and s_list[i - 1] != '?':
                avoid.append(s_list[i - 1])
            if i < n - 1 and s_list[i + 1] != '?':
                avoid.append(s_list[i + 1])
            s_list[i] = get_not(avoid)

    # Check again for consecutive identical characters
    for i in range(n - 1):
        if s_list[i] == s_list[i + 1]:
            return "-1"

    return ''.join(s_list)

def find_card_position(n: int, k: int) -> int:
    ans = 0
    for i in range(n):
        if (k & (1 << i)) != 0:
            ans += 2**(n-i-1)
    return ans
